-- Extend subrole CHECK for calisthenics shape, inversion, and sustained-capacity cards.
ALTER TABLE coaching.exercise DROP CONSTRAINT IF EXISTS exercise_phase_subrole_check;
ALTER TABLE coaching.exercise ADD CONSTRAINT exercise_phase_subrole_check
  CHECK (phase_subrole IS NULL OR phase_subrole IN (
    'raise', 'mobilize', 'activate', 'integrate', 'potentiate_bridge',
    'shape_position_intelligence',
    'shape_control',
    'inversion_foundation',
    'rolling_transition',
    'locomotion_coordination',
    'rotation_inversion_tumbling_foundations',
    'locomotion_sprint_mechanics',
    'balance_coordination_rhythm',
    'perception_action_reactive_movement',
    'acceleration_start_speed',
    'max_velocity_exposure',
    'elastic_stiffness_plyometric_rudiments',
    'jump_throw_explosive_power',
    'deceleration_cod_power',
    'reactive_agility_tumbling_output',
    'squat_knee_dominant_strength',
    'hinge_posterior_chain_strength',
    'upper_body_push_strength',
    'pull_hang_grip_strength',
    'carry_trunk_loaded_bracing_strength',
    'tissue_capacity_isometric_eccentric_accessory',
    'landing_braking_control',
    'single_leg_balance_foot_ankle_hip_control',
    'trunk_pelvis_anti_movement_control',
    'scapular_wrist_hand_support_resilience',
    'slow_eccentric_isometric_joint_resilience',
    'conditioning_intervals',
    'bodyweight_strength_endurance',
    'low_amplitude_elastic_conditioning',
    'crawl_carry_repeatability'
  ));

-- prepare_and_access calisthenics slots
INSERT INTO coaching.phase_order_slot (key, name, description, phase_id, order_index, freshness_sensitivity, subrole_key)
SELECT v.key, v.name, v.description, sp.id, v.order_index, v.freshness_sensitivity, v.subrole_key
FROM coaching.session_phase sp
CROSS JOIN (VALUES
  ('shoulder_hip_calf_access', 'Shoulder Hip Calf Access', 'Hand-support mobility flow — Rocking Plank to Down Dog.', 151, 2, 'mobilize'),
  ('wrist_forearm_access', 'Wrist Forearm Access', 'Wrist access — Quadruped Wrist Pronation Supination Shifts.', 152, 2, 'mobilize'),
  ('scapular_push_support_activation', 'Scapular Push Support Activation', 'Scapular control prep — Scapular Push-Up.', 153, 2, 'activate'),
  ('quadruped_hover_brace_activation', 'Quadruped Hover Brace Activation', 'Quadruped brace activation — Beast Hold.', 154, 2, 'activate'),
  ('contralateral_crawl_prep', 'Contralateral Crawl Prep', 'Crawl pattern prep — Bear Crawl Prep.', 155, 2, 'activate'),
  ('crab_reach_hip_shoulder_access', 'Crab Reach Hip Shoulder Access', 'Posterior chain and shoulder access — Crab Reach.', 156, 2, 'mobilize'),
  ('lunge_plank_global_access', 'Lunge Plank Global Access', 'Lunge-to-plank access flow — World''s Greatest Stretch to Plank.', 157, 2, 'mobilize'),
  ('deep_squat_ankle_hip_access', 'Deep Squat Ankle Hip Access', 'Squat access — Deep Squat Pry with Reach.', 158, 2, 'mobilize'),
  ('hollow_body_activation', 'Hollow Body Activation', 'Body shape control — Hollow Body Hold.', 159, 2, 'activate'),
  ('supine_anti_extension_activation', 'Supine Anti Extension Activation', 'Supine trunk control — Dead Bug.', 160, 2, 'activate')
) AS v(key, name, description, order_index, freshness_sensitivity, subrole_key)
WHERE sp.key = 'prepare_and_access'
ON CONFLICT (key) DO UPDATE SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  phase_id = EXCLUDED.phase_id,
  order_index = EXCLUDED.order_index,
  freshness_sensitivity = EXCLUDED.freshness_sensitivity,
  subrole_key = EXCLUDED.subrole_key;

