-- Insert 32 new calisthenics exercises
INSERT INTO coaching.exercise (
  facility_id, name, slug, description, sport_id, skill_level, age_min,
  default_sets, default_reps, default_work_seconds, default_rest_seconds, est_seconds_per_set,
  is_published, visibility,
  card_summary, coach_language, athlete_language,
  movement_family, primary_phase_key, phase_subrole, primary_order_slot,
  movement_requirements, coaching_execution
)
SELECT
  f.id,
  d.name, d.slug, d.description,
  (SELECT id FROM coaching.sport WHERE key = 'fitness'),
  d.skill::public.skill_level,
  d.age_min,
  d.sets, d.reps, d.work, d.rest, d.est,
  TRUE, 'facility',
  d.summary, d.coach_lang, d.athlete_lang,
  d.family, d.phase_key, d.subrole, d.slot,
  d.req::jsonb, d.exec::jsonb
FROM (VALUES
  ('Rocking Plank to Down Dog', 'rocking-plank-to-down-dog', 'Move from tall plank into a down-dog shape and back with controlled shoulder, rib, and hip position.', 'BEGINNER', 8, 1, 6, NULL, 15, 45, 'Bodyweight flow that opens calves, hamstrings, shoulders, and trunk while introducing light hand support.', 'Primary subrole: Mobilize. Place in Prepare & Access when the intent is hand-support mobility flow and the athlete can maintain clean bodyweight leverage, breathing, and joint position.', 'Push the floor away.', 'Hand-support mobility flow', 'prepare_and_access', 'mobilize', 'shoulder_hip_calf_access', '{"primary_joint_actions":["shoulder_flexion","spine_extension_control","hip_flexion","ankle_dorsiflexion"],"primary_tissues":["shoulder_stabilizers","wrist_support_tissues","hamstrings","calves","anterior_core"],"primary_motor_control_demands":["bodyweight_leverage_control","alignment_under_bodyweight_load","controlled_transition_or_hold"],"postural_shape":"Hand-support mobility flow","breathing_demand":"controlled","balance_demand":"stable","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Move from tall plank into a down-dog shape and back with controlled shoulder, rib, and hip position.","setup":["Choose the regression or leverage that lets the athlete perform Rocking Plank to Down Dog without pain.","Set the surface, support, wall, bar, box, or mat so it cannot move unexpectedly.","Start in the base body position with ribs, pelvis, shoulders, and hands/feet organized before the first rep."],"execution_steps":["Create tension before moving.","Move from tall plank into a down-dog shape and back with controlled shoulder, rib, and hip position.","Move through only the range the athlete can own.","Return or reset with the same posture and control used at the start.","Stop the set when the quality gate is no longer met."],"coach_cues":["Push the floor away","Ribs down","Long spine","Heels reach"],"common_faults":["Sagging plank","Shrugged shoulders","Rushing the transition","Painful wrist pressure"]}'::jsonb),
  ('Quadruped Wrist Pronation Supination Shifts', 'quadruped-wrist-pronation-supination-shifts', 'Rock in quadruped while gently changing hand orientation to expose the wrists, palms, and forearms to controlled weight bearing.', 'BEGINNER', 8, 1, 6, NULL, 15, 45, 'Low-load wrist and forearm access drill for hand-support preparation.', 'Primary subrole: Mobilize. Place in Prepare & Access when the intent is wrist access and the athlete can maintain clean bodyweight leverage, breathing, and joint position.', 'Gentle pressure.', 'Wrist access', 'prepare_and_access', 'mobilize', 'wrist_forearm_access', '{"primary_joint_actions":["wrist_extension","forearm_pronation_supination","shoulder_support"],"primary_tissues":["wrist_flexors","wrist_extensors","forearm_pronators","forearm_supinators"],"primary_motor_control_demands":["bodyweight_leverage_control","alignment_under_bodyweight_load","controlled_transition_or_hold"],"postural_shape":"Wrist access","breathing_demand":"controlled","balance_demand":"stable","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Rock in quadruped while gently changing hand orientation to expose the wrists, palms, and forearms to controlled weight bearing.","setup":["Choose the regression or leverage that lets the athlete perform Quadruped Wrist Pronation Supination Shifts without pain.","Set the surface, support, wall, bar, box, or mat so it cannot move unexpectedly.","Start in the base body position with ribs, pelvis, shoulders, and hands/feet organized before the first rep."],"execution_steps":["Create tension before moving.","Rock in quadruped while gently changing hand orientation to expose the wrists, palms, and forearms to controlled weight bearing.","Move through only the range the athlete can own.","Return or reset with the same posture and control used at the start.","Stop the set when the quality gate is no longer met."],"coach_cues":["Gentle pressure","Spread fingers","Small rocks","Stay pain free"],"common_faults":["Dumping into the wrist","Locked elbows with pain","Moving too fast","Ignoring numbness or tingling"]}'::jsonb),
  ('Beast Hold', 'beast-hold', 'From quadruped, lift the knees slightly off the floor and hold a quiet, square position with steady breathing.', 'BEGINNER', 8, 1, 6, NULL, 15, 45, 'Low hover hold that activates trunk, shoulders, hips, and foot pressure before crawls or strength work.', 'Primary subrole: Activate. Place in Prepare & Access when the intent is quadruped brace activation and the athlete can maintain clean bodyweight leverage, breathing, and joint position.', 'Knees hover.', 'Quadruped brace activation', 'prepare_and_access', 'activate', 'quadruped_hover_brace_activation', '{"primary_joint_actions":["trunk_bracing","shoulder_support","hip_flexion_hold","knee_hover_control"],"primary_tissues":["anterior_core","serratus_anterior","quadriceps","hip_flexors","wrist_support_tissues"],"primary_motor_control_demands":["bodyweight_leverage_control","alignment_under_bodyweight_load","controlled_transition_or_hold"],"postural_shape":"Quadruped brace activation","breathing_demand":"controlled","balance_demand":"moderate","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"From quadruped, lift the knees slightly off the floor and hold a quiet, square position with steady breathing.","setup":["Choose the regression or leverage that lets the athlete perform Beast Hold without pain.","Set the surface, support, wall, bar, box, or mat so it cannot move unexpectedly.","Start in the base body position with ribs, pelvis, shoulders, and hands/feet organized before the first rep."],"execution_steps":["Create tension before moving.","From quadruped, lift the knees slightly off the floor and hold a quiet, square position with steady breathing.","Move through only the range the athlete can own.","Return or reset with the same posture and control used at the start.","Stop the set when the quality gate is no longer met."],"coach_cues":["Knees one inch","Quiet back","Push the floor","Breathe behind the brace"],"common_faults":["Hips too high","Shoulders collapse","Breath holding","Weight dumped into wrists"]}'::jsonb),
  ('Bear Crawl Prep', 'bear-crawl-prep', 'Move opposite hand and foot in a small controlled bear crawl while maintaining a steady trunk and quiet hip height.', 'BEGINNER', 8, 1, 6, NULL, 15, 45, 'Slow contralateral crawl pattern that prepares shoulders, wrists, trunk, hips, and feet for floor-based locomotion.', 'Primary subrole: Activate. Place in Prepare & Access when the intent is crawl pattern prep and the athlete can maintain clean bodyweight leverage, breathing, and joint position.', 'Small steps.', 'Crawl pattern prep', 'prepare_and_access', 'activate', 'contralateral_crawl_prep', '{"primary_joint_actions":["contralateral_locomotion","shoulder_closed_chain_support","hip_flexion_extension","trunk_anti_rotation"],"primary_tissues":["serratus_anterior","wrist_support_tissues","anterior_core","hip_flexors","calves"],"primary_motor_control_demands":["bodyweight_leverage_control","alignment_under_bodyweight_load","controlled_transition_or_hold"],"postural_shape":"Crawl pattern prep","breathing_demand":"controlled","balance_demand":"moderate","coordination_demand":"high","impact_level":0}'::jsonb, '{"movement_description":"Move opposite hand and foot in a small controlled bear crawl while maintaining a steady trunk and quiet hip height.","setup":["Choose the regression or leverage that lets the athlete perform Bear Crawl Prep without pain.","Set the surface, support, wall, bar, box, or mat so it cannot move unexpectedly.","Start in the base body position with ribs, pelvis, shoulders, and hands/feet organized before the first rep."],"execution_steps":["Create tension before moving.","Move opposite hand and foot in a small controlled bear crawl while maintaining a steady trunk and quiet hip height.","Move through only the range the athlete can own.","Return or reset with the same posture and control used at the start.","Stop the set when the quality gate is no longer met."],"coach_cues":["Opposite hand and foot","Hips quiet","Small steps","No bouncing"],"common_faults":["Rocking side to side","Knees too high","Hands slap the ground","Rushing into fatigue"]}'::jsonb),
  ('World''s Greatest Stretch to Plank', 'worlds-greatest-stretch-to-plank', 'Step to a long lunge from plank, add controlled reach or rotation, then return to plank without losing trunk position.', 'BEGINNER', 8, 1, 6, NULL, 15, 45, 'Integrated lunge and plank flow that opens hips, hamstrings, T-spine, and shoulders before calisthenics work.', 'Primary subrole: Mobilize. Place in Prepare & Access when the intent is lunge-to-plank access flow and the athlete can maintain clean bodyweight leverage, breathing, and joint position.', 'Long lunge, long reach.', 'Lunge-to-plank access flow', 'prepare_and_access', 'mobilize', 'lunge_plank_global_access', '{"primary_joint_actions":["hip_extension","ankle_dorsiflexion","thoracic_rotation","shoulder_support"],"primary_tissues":["hip_flexors","adductors","hamstrings","obliques","shoulder_stabilizers"],"primary_motor_control_demands":["bodyweight_leverage_control","alignment_under_bodyweight_load","controlled_transition_or_hold"],"postural_shape":"Lunge-to-plank access flow","breathing_demand":"controlled","balance_demand":"stable","coordination_demand":"high","impact_level":0}'::jsonb, '{"movement_description":"Step to a long lunge from plank, add controlled reach or rotation, then return to plank without losing trunk position.","setup":["Choose the regression or leverage that lets the athlete perform World''s Greatest Stretch to Plank without pain.","Set the surface, support, wall, bar, box, or mat so it cannot move unexpectedly.","Start in the base body position with ribs, pelvis, shoulders, and hands/feet organized before the first rep."],"execution_steps":["Create tension before moving.","Step to a long lunge from plank, add controlled reach or rotation, then return to plank without losing trunk position.","Move through only the range the athlete can own.","Return or reset with the same posture and control used at the start.","Stop the set when the quality gate is no longer met."],"coach_cues":["Step outside hand","Back leg long","Reach and breathe","Return under control"],"common_faults":["Short lunge","Collapsed plank","Bouncing the stretch","Knee pain from poor line"]}'::jsonb),
  ('Deep Squat Pry with Reach', 'deep-squat-pry-with-reach', 'Hold a deep squat position, gently pry the hips open, and add small reaches while maintaining foot pressure and posture.', 'BEGINNER', 8, 1, 6, NULL, 15, 45, 'Controlled deep-squat mobility drill that builds ankle, hip, and thoracic access for bodyweight squat patterns.', 'Primary subrole: Mobilize. Place in Prepare & Access when the intent is squat access and the athlete can maintain clean bodyweight leverage, breathing, and joint position.', 'Own the bottom.', 'Squat access', 'prepare_and_access', 'mobilize', 'deep_squat_ankle_hip_access', '{"primary_joint_actions":["hip_external_rotation","ankle_dorsiflexion","knee_flexion","thoracic_rotation"],"primary_tissues":["adductors","glutes","calves","quadriceps","spinal_stabilizers"],"primary_motor_control_demands":["bodyweight_leverage_control","alignment_under_bodyweight_load","controlled_transition_or_hold"],"postural_shape":"Squat access","breathing_demand":"controlled","balance_demand":"moderate","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Hold a deep squat position, gently pry the hips open, and add small reaches while maintaining foot pressure and posture.","setup":["Choose the regression or leverage that lets the athlete perform Deep Squat Pry with Reach without pain.","Set the surface, support, wall, bar, box, or mat so it cannot move unexpectedly.","Start in the base body position with ribs, pelvis, shoulders, and hands/feet organized before the first rep."],"execution_steps":["Create tension before moving.","Hold a deep squat position, gently pry the hips open, and add small reaches while maintaining foot pressure and posture.","Move through only the range the athlete can own.","Return or reset with the same posture and control used at the start.","Stop the set when the quality gate is no longer met."],"coach_cues":["Whole foot","Elbows guide knees","Chest proud","Breathe low"],"common_faults":["Heels lift hard","Knees collapse","Rounded painful spine","Forcing depth"]}'::jsonb),
  ('Tuck-Up', 'tuck-up', 'Move from hollow or long-body position into a tight tuck, then return under control without using momentum.', 'BEGINNER', 8, 2, 5, NULL, 30, 60, 'Tuck compression drill that builds coordinated trunk flexion, hip flexion, and controlled shape changes.', 'Primary subrole: Shape Control. Place in Movement Intelligence when the intent is compression shape and the athlete can maintain clean bodyweight leverage, breathing, and joint position.', 'Snap to shape, control out.', 'Compression shape', 'movement_intelligence', 'shape_control', 'tuck_up_progression', '{"primary_joint_actions":["trunk_flexion","hip_flexion","posterior_pelvic_tilt"],"primary_tissues":["anterior_core","hip_flexors","rectus_abdominis"],"primary_motor_control_demands":["bodyweight_leverage_control","alignment_under_bodyweight_load","controlled_transition_or_hold"],"postural_shape":"Compression shape","breathing_demand":"controlled","balance_demand":"stable","coordination_demand":"high","impact_level":0}'::jsonb, '{"movement_description":"Move from hollow or long-body position into a tight tuck, then return under control without using momentum.","setup":["Choose the regression or leverage that lets the athlete perform Tuck-Up without pain.","Set the surface, support, wall, bar, box, or mat so it cannot move unexpectedly.","Start in the base body position with ribs, pelvis, shoulders, and hands/feet organized before the first rep."],"execution_steps":["Create tension before moving.","Move from hollow or long-body position into a tight tuck, then return under control without using momentum.","Move through only the range the athlete can own.","Return or reset with the same posture and control used at the start.","Stop the set when the quality gate is no longer met."],"coach_cues":["Knees in","Ribs down","Control the lower","No throwing arms"],"common_faults":["Momentum swing","Low back arch","Neck pull","Feet crash down"]}'::jsonb),
