  ('Decline Push-Up', 'decline-push-up', 'Place feet on a stable box and perform a push-up while keeping shoulders, ribs, and pelvis controlled.', 'BEGINNER', 8, 3, 6, NULL, 75, 50, 'Feet-elevated push-up that increases upper-body loading and anterior trunk demand.', 'Primary subrole: Upper-Body Push Strength. Place in Capacity when the intent is elevated-feet push strength and the athlete can maintain clean bodyweight leverage, breathing, and joint position.', 'Long body, strong press.', 'Elevated-feet push strength', 'capacity', 'upper_body_push_strength', 'decline_push_strength', '{"primary_joint_actions":["elbow_flexion_extension","shoulder_horizontal_flexion","scapular_control","anti_extension_bracing"],"primary_tissues":["pectorals","triceps","anterior_deltoids","serratus_anterior","anterior_core"],"primary_motor_control_demands":["bodyweight_leverage_control","alignment_under_bodyweight_load","controlled_transition_or_hold"],"postural_shape":"Elevated-feet push strength","breathing_demand":"controlled","balance_demand":"stable","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Place feet on a stable box and perform a push-up while keeping shoulders, ribs, and pelvis controlled.","setup":["Choose the regression or leverage that lets the athlete perform Decline Push-Up without pain.","Set the surface, support, wall, bar, box, or mat so it cannot move unexpectedly.","Start in the base body position with ribs, pelvis, shoulders, and hands/feet organized before the first rep."],"execution_steps":["Create tension before moving.","Place feet on a stable box and perform a push-up while keeping shoulders, ribs, and pelvis controlled.","Move through only the range the athlete can own.","Return or reset with the same posture and control used at the start.","Stop the set when the quality gate is no longer met."],"coach_cues":["Ribs down","Press tall","Chest lowers as one piece","Feet stay quiet"],"common_faults":["Box too high","Low ba