  ('Parallel-Bar Dip Progression', 'parallel-bar-dip-progression', 'Use parallel bars, rings, or a stable support to lower and press through a pain-free dip range with shoulder control.', 'INTERMEDIATE', 8, 3, 6, NULL, 75, 50, 'Bodyweight dip progression that builds pressing strength through shoulder extension, elbow extension, and support control.', 'Primary subrole: Upper-Body Push Strength. Place in Capacity when the intent is bodyweight dip strength and the athlete can maintain clean bodyweight leverage, breathing, and joint position.', 'Shoulders controlled.', 'Bodyweight dip strength', 'capacity', 'upper_body_push_strength', 'dip_support_press_strength', '{"primary_joint_actions":["shoulder_extension_control","elbow_flexion_extension","scapular_depression","trunk_bracing"],"primary_tissues":["triceps","pectorals","anterior_deltoids","lower_trapezius"],"primary_motor_control_demands":["bodyweight_leverage_control","alignment_under_bodyweight_load","controlled_transition_or_hold"],"postural_shape":"Bodyweight dip strength","breathing_demand":"controlled","balance_demand":"moderate","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Use parallel bars, rings, or a stable support to lower and press through a pain-free dip range with shoulder control.","setup":["Choose the regression or leverage that lets the athlete perform Parallel-Bar Dip Progression without pain.","Set the surface, support, wall, bar, box, or mat so it cannot move unexpectedly.","Start in the base body position with ribs, pelvis, shoulders, and hands/feet organized before the first rep."],"execution_steps":["Create tension before moving.","Use parallel bars, rings, or a stable support to lower and press through a pain-free dip range with shoulder control.","Move through only the range the athlete can own.","Return or reset with the same posture and control used at the start.","Stop the set when the quality gate is no longer met."],"coach_cues":["Shoulders down","Control depth","Press tall","No bounce"],"common_faults":["Shoulders dump forward","Range too deep","Elbows flare painfully","Support unstable"]}'::jsonb),
  ('Strict Pull-Up', 'strict-pull-up', 'Hang from a secure bar and pull the chin above the bar without kipping, swinging, or losing shoulder control.', 'INTERMEDIATE', 8, 3, 6, NULL, 75, 50, 'Foundational vertical pulling exercise that builds lats, upper back, arms, grip, and trunk tension.', 'Primary subrole: Pull / Hang / Grip Strength. Place in Capacity when the intent is vertical pull strength and the athlete can maintain clean bodyweight leverage, breathing, and joint position.', 'Pull clean.', 'Vertical pull strength', 'capacity', 'pull_hang_grip_strength', 'strict_vertical_pull_strength', '{"primary_joint_actions":["elbow_flexion","shoulder_extension_adduction","scapular_depression","grip_isometric"],"primary_tissues":["lats","biceps","lower_trapezius","forearms","anterior_core"],"primary_motor_control_demands":["bodyweight_leverage_control","alignment_under_bodyweight_load","controlled_transition_or_hold"],"postural_shape":"Vertical pull strength","breathing_demand":"controlled","balance_demand":"stable","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Hang from a secure bar and pull the chin above the bar without kipping, swinging, or losing shoulder control.","setup":["Choose the regression or leverage that lets the athlete perform Strict Pull-Up without pain.","Set the surface, support, wall, bar, box, or mat so it cannot move unexpectedly.","Start in the base body position with ribs, pelvis, shoulders, and hands/feet organized before the first rep."],"execution_steps":["Create tension before moving.","Hang from a secure bar and pull the chin above the bar without kipping, swinging, or losing shoulder control.","Move through only the range the athlete can own.","Return or reset with the same posture and control used at the start.","Stop the set when the quality gate is no longer met."],"coach_cues":["Active hang","Ribs down","Pull elbows to ribs","Lower clean"],"common_faults":["Kipping unintentionally","Chin reach","Shoulders dump","Grip unsafe"]}'::jsonb),
  ('Tuck Hanging Knee Raise', 'tuck-hanging-knee-raise', 'Hang from a bar and raise the knees toward the chest without swinging.', 'BEGINNER', 8, 3, 6, NULL, 75, 50, 'Hanging knee raise that builds grip, shoulder control, anterior core strength, and hip flexion capacity.', 'Primary subrole: Pull / Hang / Grip Strength. Place in Capacity when the intent is hanging core strength and the athlete can maintain clean bodyweight leverage, breathing, and joint position.', 'No swing.', 'Hanging core strength', 'capacity', 'pull_hang_grip_strength', 'hanging_core_strength', '{"primary_joint_actions":["hip_flexion","posterior_pelvic_tilt","grip_isometric","scapular_control"],"primary_tissues":["anterior_core","hip_flexors","forearms","lats"],"primary_motor_control_demands":["bodyweight_leverage_control","alignment_under_bodyweight_load","controlled_transition_or_hold"],"postural_shape":"Hanging core strength","breathing_demand":"controlled","balance_demand":"moderate","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Hang from a bar and raise the knees toward the chest without swinging.","setup":["Choose the regression or leverage that lets the athlete perform Tuck Hanging Knee Raise without pain.","Set the surface, support, wall, bar, box, or mat so it cannot move unexpectedly.","Start in the base body position with ribs, pelvis, shoulders, and hands/feet organized before the first rep."],"execution_steps":["Create tension before moving.","Hang from a bar and raise the knees toward the chest without swinging.","Move through only the range the athlete can own.","Return or reset with the same posture and control used at the start.","Stop the set when the quality gate is no longer met."],"coach_cues":["No swing","Knees up","Ribs down","Slow lower"],"common_faults":["Swinging","Shoulders dump","Low back arches","Grip fails"]}'::jsonb),
  ('Active Hang', 'active-hang', 'Hang from a secure bar while keeping shoulders active, ribs organized, and grip controlled.', 'BEGINNER', 8, 2, NULL, 20, 45, 40, 'Hanging shoulder-control drill that builds grip, scapular depression, and overhead tissue tolerance.', 'Primary subrole: Scapular / Wrist / Hand-Support Resilience. Place in Resilience when the intent is shoulder hang resilience and the athlete can maintain clean bodyweight leverage, breathing, and joint position.', 'Shoulders active.', 'Shoulder hang resilience', 'resilience', 'scapular_wrist_hand_support_resilience', 'active_hang_shoulder_control', '{"primary_joint_actions":["grip_isometric","scapular_depression","shoulder_flexion_overhead","trunk_bracing"],"primary_tissues":["forearms","lats","lower_trapezius","rotator_cuff","anterior_core"],"primary_motor_control_demands":["bodyweight_leverage_control","alignment_under_bodyweight_load","controlled_transition_or_hold"],"postural_shape":"Shoulder hang resilience","breathing_demand":"controlled","balance_demand":"stable","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Hang from a secure bar while keeping shoulders active, ribs organized, and grip controlled.","setup":["Choose the regression or leverage that lets the athlete perform Active Hang without pain.","Set the surface, support, wall, bar, box, or mat so it cannot move unexpectedly.","Start in the base body position with ribs, pelvis, shoulders, and hands/feet organized before the first rep."],"execution_steps":["Create tension before moving.","Hang from a secure bar while keeping shoulders active, ribs organized, and grip controlled.","Move through only the range the athlete can own.","Return or reset with the same posture and control used at the start.","Stop the set when the quality gate is no longer met."],"coach_cues":["Active shoulders","Long neck","Ribs down","Step down before grip fails"],"common_faults":["Dead shoulder dump","Swinging","Grip slips","Breath holding"]}'::jsonb),
  ('Flexed-Arm Hang', 'flexed-arm-hang', 'Start with the chin above the bar and hold the top pull-up position with control.', 'INTERMEDIATE', 8, 3, NULL, 20, 75, 40, 'Top-position isometric hang that builds vertical pulling strength, grip, and scapular control.', 'Primary subrole: Pull / Hang / Grip Strength. Place in Capacity when the intent is vertical pull isometric and the athlete can maintain clean bodyweight leverage, breathing, and joint position.', 'Chest tall.', 'Vertical pull isometric', 'capacity', 'pull_hang_grip_strength', 'vertical_pull_isometric_strength', '{"primary_joint_actions":["elbow_flexion_isometric","scapular_depression","grip_isometric","trunk_bracing"],"primary_tissues":["lats","biceps","forearms","lower_trapezius","anterior_core"],"primary_motor_control_demands":["bodyweight_leverage_control","alignment_under_bodyweight_load","controlled_transition_or_hold"],"postural_shape":"Vertical pull isometric","breathing_demand":"controlled","balance_demand":"moderate","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Start with the chin above the bar and hold the top pull-up position with control.","setup":["Choose the regression or leverage that lets the athlete perform Flexed-Arm Hang without pain.","Set the surface, support, wall, bar, box, or mat so it cannot move unexpectedly.","Start in the base body position with ribs, pelvis, shoulders, and hands/feet organized before the first rep."],"execution_steps":["Create tension before moving.","Start with the chin above the bar and hold the top pull-up position with control.","Move through only the range the athlete can own.","Return or reset with the same posture and control used at the start.","Stop the set when the quality gate is no longer met."],"coach_cues":["Chest tall","Chin over bar","Shoulders active","Step down clean"],"common_faults":["Chin reach","Shoulders dump","Grip slipping","Holding past control"]}'::jsonb),
  ('Mountain Climber', 'mountain-climber', 'From a high plank, alternate knee drives while maintaining shoulder position, trunk control, and repeatable pace.', 'BEGINNER', 8, 3, NULL, 30, 30, 60, 'Plank-based conditioning drill that trains trunk stiffness, hip drive, shoulder support, and repeatable coordination.', 'Primary subrole: Bodyweight Strength Endurance. Place in Sustained Capacity when the intent is bodyweight trunk repeatability and the athlete can maintain clean bodyweight leverage, breathing, and joint position.', 'Fast legs, quiet hips.', 'Bodyweight trunk repeatability', 'sustained_capacity', 'bodyweight_strength_endurance', 'plank_knee_drive_repeatability', '{"primary_joint_actions":["alternating_hip_flexion","shoulder_support","anti_extension_bracing","foot_exchange"],"primary_tissues":["hip_flexors","anterior_core","serratus_anterior","calves"],"primary_motor_control_demands":["bodyweight_leverage_control","alignment_under_bodyweight_load","controlled_transition_or_hold"],"postural_shape":"Bodyweight trunk repeatability","breathing_demand":"elevated_but_controlled","balance_demand":"stable","coordination_demand":"high","impact_level":1}'::jsonb, '{"movement_description":"From a high plank, alternate knee drives while maintaining shoulder position, trunk control, and repeatable pace.","setup":["Choose the regression or leverage that lets the athlete perform Mountain Climber without pain.","Set the surface, support, wall, bar, box, or mat so it cannot move unexpectedly.","Start in the base body position with ribs, pelvis, shoulders, and hands/feet organized before the first rep."],"execution_steps":["Create tension before moving.","From a high plank, alternate knee drives while maintaining shoulder position, trunk control, and repeatable pace.","Move through only the range the athlete can own.","Return or reset with the same posture and control used at the start.","Stop the set when the quality gate is no longer met."],"coach_cues":["Quiet hips","Knees under chest","Push floor","Pace you can own"],"common_faults":["Hips bouncing","Shoulders collapse","Feet slam","Fatigue destroys plank"]}'::jsonb),
  ('Squat Thrust', 'squat-thrust', 'Move from standing to plank and back to squat or stand with controlled foot placement.', 'BEGINNER', 8, 3, NULL, 30, 30, 60, 'Simple bodyweight conditioning movement that trains plank-to-squat transitions without the push-up or jump of a full burpee.', 'Primary subrole: Bodyweight Strength Endurance. Place in Sustained Capacity when the intent is bodyweight conditioning movement and the athlete can maintain clean bodyweight leverage, breathing, and joint position.', 'Hands down.', 'Bodyweight conditioning movement', 'sustained_capacity', 'bodyweight_strength_endurance', 'low_skill_burpee_pattern', '{"primary_joint_actions":["squat_to_plank_transition","shoulder_support","hip_flexion_extension","trunk_bracing"],"primary_tissues":["anterior_core","quadriceps","glutes","shoulder_stabilizers","wrist_support_tissues"],"primary_motor_control_demands":["bodyweight_leverage_control","alignment_under_bodyweight_load","controlled_transition_or_hold"],"postural_shape":"Bodyweight conditioning movement","breathing_demand":"elevated_but_controlled","balance_demand":"stable","coordination_demand":"high","impact_level":1}'::jsonb, '{"movement_description":"Move from standing to plank and back to squat or stand with controlled foot placement.","setup":["Choose the regression or leverage that lets the athlete perform Squat Thrust without pain.","Set the surface, support, wall, bar, box, or mat so it cannot move unexpectedly.","Start in the base body position with ribs, pelvis, shoulders, and hands/feet organized before the first rep."],"execution_steps":["Create tension before moving.","Move from standing to plank and back to squat or stand with controlled foot placement.","Move through only the range the athlete can own.","Return or reset with the same posture and control used at the start.","Stop the set when the quality gate is no longer met."],"coach_cues":["Hands down","Feet back","Feet in","Stand tall"],"common_faults":["Feet crash wide","Sagging plank","Rushing to sloppy reps","Jumping when low-impact is intended"]}'::jsonb),
  ('Burpee Step-Back', 'burpee-step-back', 'Squat down, step back to plank, step back in, and stand tall at a controlled repeatable pace.', 'BEGINNER', 8, 3, NULL, 30, 30, 60, 'Low-impact calisthenics conditioning movement that trains full-body transition capacity without a jump or push-up requirement.', 'Primary subrole: Bodyweight Strength Endurance. Place in Sustained Capacity when the intent is low-impact burpee variation and the athlete can maintain clean bodyweight leverage, breathing, and joint position.', 'Step back.', 'Low-impact burpee variation', 'sustained_capacity', 'bodyweight_strength_endurance', 'low_impact_burpee_repeatability', '{"primary_joint_actions":["squat_to_plank_transition","alternating_step_back","shoulder_support","trunk_bracing"],"primary_tissues":["quadriceps","glutes","hip_flexors","anterior_core","shoulder_stabilizers"],"primary_motor_control_demands":["bodyweight_leverage_control","alignment_under_bodyweight_load","controlled_transition_or_hold"],"postural_shape":"Low-impact burpee variation","breathing_demand":"elevated_but_controlled","balance_demand":"stable","coordination_demand":"high","impact_level":0}'::jsonb, '{"movement_description":"Squat down, step back to plank, step back in, and stand tall at a controlled repeatable pace.","setup":["Choose the regression or leverage that lets the athlete perform Burpee Step-Back without pain.","Set the surface, support, wall, bar, box, or mat so it cannot move unexpectedly.","Start in the base body position with ribs, pelvis, shoulders, and hands/feet organized before the first rep."],"execution_steps":["Create tension before moving.","Squat down, step back to plank, step back in, and stand tall at a controlled repeatable pace.","Move through only the range the athlete can own.","Return or reset with the same posture and control used at the start.","Stop the set when the quality gate is no longer met."],"coach_cues":["Step back","Plank first","Step in","Stand tall"],"common_faults":["Hands too far forward","Plank sag","Standing halfway","Turning low impact into chaotic speed"]}'::jsonb),
  ('Skater Step', 'skater-step', 'Step side-to-side in a skater pattern, reaching the opposite leg behind without turning it into a maximal bound.', 'BEGINNER', 8, 3, NULL, 30, 30, 60, 'Low-impact lateral step pattern that develops lateral rhythm, balance, and sustained side-to-side movement without high plyometric demand.', 'Primary subrole: Low-Amplitude Elastic Conditioning. Place in Sustained Capacity when the intent is low-amplitude lateral conditioning and the athlete can maintain clean bodyweight leverage, breathing, and joint position.', 'Step, don''t leap.', 'Low-amplitude lateral conditioning', 'sustained_capacity', 'low_amplitude_elastic_conditioning', 'lateral_rhythm_repeatability', '{"primary_joint_actions":["lateral_weight_shift","single_leg_balance","hip_abduction_adduction","controlled_landing"],"primary_tissues":["gluteus_medius","adductors","calves","quadriceps"],"primary_motor_control_demands":["bodyweight_leverage_control","alignment_under_bodyweight_load","controlled_transition_or_hold"],"postural_shape":"Low-amplitude lateral conditioning","breathing_demand":"elevated_but_controlled","balance_demand":"moderate","coordination_demand":"high","impact_level":1}'::jsonb, '{"movement_description":"Step side-to-side in a skater pattern, reaching the opposite leg behind without turning it into a maximal bound.","setup":["Choose the regression or leverage that lets the athlete perform Skater Step without pain.","Set the surface, support, wall, bar, box, or mat so it cannot move unexpectedly.","Start in the base body position with ribs, pelvis, shoulders, and hands/feet organized before the first rep."],"execution_steps":["Create tension before moving.","Step side-to-side in a skater pattern, reaching the opposite leg behind without turning it into a maximal bound.","Move through only the range the athlete can own.","Return or reset with the same posture and control used at the start.","Stop the set when the quality gate is no longer met."],"coach_cues":["Step, don''t leap","Knee tracks","Soft touch","Rhythm first"],"common_faults":["Max bounding","Knee caves","Loud contacts","Speed before control"]}'::jsonb),
  ('Crab Walk', 'crab-walk', 'Move in a crab position with hips lifted while stepping hands and feet under control.', 'BEGINNER', 8, 3, NULL, 30, 30, 60, 'Reverse quadruped locomotion that develops shoulder support, hip extension, coordination, and full-body work capacity.', 'Primary subrole: Crawl / Carry Repeatability. Place in Sustained Capacity when the intent is crawl repeatability and the athlete can maintain clean bodyweight leverage, breathing, and joint position.', 'Hips up.', 'Crawl repeatability', 'sustained_capacity', 'crawl_carry_repeatability', 'crab_walk_repeatability', '{"primary_joint_actions":["shoulder_extension_support","hip_extension_isometric","contralateral_locomotion","trunk_bracing"],"primary_tissues":["posterior_shoulder","triceps","glutes","wrist_support_tissues","anterior_core"],"primary_motor_control_demands":["bodyweight_leverage_control","alignment_under_bodyweight_load","controlled_transition_or_hold"],"postural_shape":"Crawl repeatability","breathing_demand":"elevated_but_controlled","balance_demand":"moderate","coordination_demand":"high","impact_level":0}'::jsonb, '{"movement_description":"Move in a crab position with hips lifted while stepping hands and feet under control.","setup":["Choose the regression or leverage that lets the athlete perform Crab Walk without pain.","Set the surface, support, wall, bar, box, or mat so it cannot move unexpectedly.","Start in the base body position with ribs, pelvis, shoulders, and hands/feet organized before the first rep."],"execution_steps":["Create tension before moving.","Move in a crab position with hips lifted while stepping hands and feet under control.","Move through only the range the athlete can own.","Return or reset with the same posture and control used at the start.","Stop the set when the quality gate is no longer met."],"coach_cues":["Hips up","Small steps","Hands quiet","Keep space behind clear"],"common_faults":["Hips drag","Shoulders crank","Hands turned painfully","Racing into wrist fatigue"]}'::jsonb)
) AS d(name, slug, description, skill, age_min, sets, reps, work, rest, est, summary, coach_lang, athlete_lang, family, phase_key, subrole, slot, req, exec)
CROSS JOIN public.facility f
ON CONFLICT (facility_id, slug) DO NOTHING;

