INSERT INTO coaching.exercise_phase_profile (
  exercise_id, phase_id, fit_weight, role, order_slot, order_index,
  freshness_required, fatigue_sensitivity, fatigue_cost, technical_complexity, impact_level, intensity_ceiling
)
SELECT e.id, sp.id, COALESCE(m.fit_weight, 5), COALESCE(m.role, 'primary'), m.slot, pos.order_index,
  COALESCE(m.freshness_required, FALSE), COALESCE(m.fatigue_sensitivity, 2), COALESCE(m.fatigue_cost, 2),
  COALESCE(m.technical_complexity, 2), COALESCE(m.impact_level, 0), COALESCE(m.intensity_ceiling, 'moderate')
FROM (VALUES
  ('rocking-plank-to-down-dog', 'prepare_and_access', 'shoulder_hip_calf_access', 'primary', 5, FALSE, 1, 1, 2, 0, 'low'),
  ('quadruped-wrist-pronation-supination-shifts', 'prepare_and_access', 'wrist_forearm_access', 'primary', 5, FALSE, 1, 1, 2, 0, 'low'),
  ('beast-hold', 'prepare_and_access', 'quadruped_hover_brace_activation', 'primary', 5, FALSE, 1, 1, 2, 0, 'low'),
  ('bear-crawl-prep', 'prepare_and_access', 'contralateral_crawl_prep', 'primary', 5, FALSE, 1, 1, 2, 0, 'low'),
  ('worlds-greatest-stretch-to-plank', 'prepare_and_access', 'lunge_plank_global_access', 'primary', 5, FALSE, 1, 1, 2, 0, 'low'),
  ('deep-squat-pry-with-reach', 'prepare_and_access', 'deep_squat_ankle_hip_access', 'primary', 5, FALSE, 1, 1, 2, 0, 'low'),
  ('tuck-up', 'movement_intelligence', 'tuck_up_progression', 'primary', 5, TRUE, 4, 2, 4, 0, 'moderate'),
  ('v-up-progression', 'movement_intelligence', 'v_up_progression', 'primary', 5, TRUE, 4, 2, 4, 0, 'moderate'),
  ('straddle-compression-lift', 'movement_intelligence', 'straddle_compression_lift', 'primary', 5, TRUE, 4, 2, 4, 0, 'moderate'),
  ('tuck-l-sit-hold', 'movement_intelligence', 'tuck_l_sit_support_shape', 'primary', 5, TRUE, 4, 2, 4, 0, 'moderate'),
  ('wall-walk', 'movement_intelligence', 'wall_walk_inversion_entry', 'primary', 5, TRUE, 4, 2, 4, 0, 'moderate'),
  ('wall-facing-handstand-hold', 'movement_intelligence', 'handstand_line_hold', 'primary', 5, TRUE, 4, 2, 4, 0, 'moderate'),
  ('wall-facing-handstand-toe-pull', 'movement_intelligence', 'handstand_line_balance', 'primary', 5, TRUE, 4, 2, 4, 0, 'moderate'),
  ('forward-roll-to-stand', 'movement_intelligence', 'roll_to_stand_transition', 'primary', 5, TRUE, 4, 2, 4, 0, 'moderate'),
  ('lateral-ape-walk', 'movement_intelligence', 'lateral_ape_walk', 'primary', 5, TRUE, 4, 2, 4, 1, 'moderate'),
  ('prisoner-squat', 'capacity', 'upright_squat_strength', 'primary', 5, FALSE, 3, 3, 3, 0, 'high'),
  ('bulgarian-split-squat', 'capacity', 'rear_foot_elevated_split_squat_strength', 'primary', 5, FALSE, 3, 3, 3, 0, 'high'),
  ('cossack-squat', 'capacity', 'lateral_squat_strength', 'primary', 5, FALSE, 3, 3, 3, 0, 'high'),
  ('pistol-squat-to-box', 'capacity', 'single_leg_squat_box_strength', 'primary', 5, FALSE, 4, 3, 4, 0, 'high'),
  ('glute-bridge-walkout', 'resilience', 'hamstring_bridge_walkout_control', 'primary', 5, FALSE, 3, 2, 3, 0, 'moderate'),
  ('close-grip-push-up', 'capacity', 'close_grip_horizontal_push_strength', 'primary', 5, FALSE, 3, 3, 3, 0, 'high'),
  ('decline-push-up', 'capacity', 'decline_push_strength', 'primary', 5, FALSE, 3, 3, 3, 0, 'high'),
  ('parallel-bar-dip-progression', 'capacity', 'dip_support_press_strength', 'primary', 5, FALSE, 4, 3, 4, 0, 'high'),
  ('strict-pull-up', 'capacity', 'strict_vertical_pull_strength', 'primary', 5, FALSE, 4, 3, 4, 0, 'high'),
  ('tuck-hanging-knee-raise', 'capacity', 'hanging_core_strength', 'primary', 5, FALSE, 3, 3, 3, 0, 'high'),
  ('active-hang', 'resilience', 'active_hang_shoulder_control', 'primary', 5, FALSE, 3, 2, 3, 0, 'moderate'),
  ('flexed-arm-hang', 'capacity', 'vertical_pull_isometric_strength', 'primary', 5, FALSE, 4, 3, 4, 0, 'high'),
  ('mountain-climber', 'sustained_capacity', 'plank_knee_drive_repeatability', 'primary', 5, FALSE, 2, 4, 2, 1, 'high'),
  ('squat-thrust', 'sustained_capacity', 'low_skill_burpee_pattern', 'primary', 5, FALSE, 2, 4, 2, 1, 'high'),
  ('burpee-step-back', 'sustained_capacity', 'low_impact_burpee_repeatability', 'primary', 5, FALSE, 2, 4, 2, 0, 'high'),
  ('skater-step', 'sustained_capacity', 'lateral_rhythm_repeatability', 'primary', 5, FALSE, 2, 4, 2, 1, 'high'),
  ('crab-walk', 'sustained_capacity', 'crab_walk_repeatability', 'primary', 5, FALSE, 2, 4, 2, 0, 'high')
) AS m(slug, phase_key, slot, role, fit_weight, freshness_required, fatigue_sensitivity, fatigue_cost, technical_complexity, impact_level, intensity_ceiling)
JOIN coaching.exercise e ON e.slug = m.slug
JOIN coaching.session_phase sp ON sp.key = m.phase_key
JOIN coaching.phase_order_slot pos ON pos.key = m.slot AND pos.phase_id = sp.id
ON CONFLICT (exercise_id, phase_id) DO UPDATE SET
  role = EXCLUDED.role, order_slot = EXCLUDED.order_slot, fit_weight = EXCLUDED.fit_weight,
  freshness_required = EXCLUDED.freshness_required, fatigue_sensitivity = EXCLUDED.fatigue_sensitivity,
  fatigue_cost = EXCLUDED.fatigue_cost, technical_complexity = EXCLUDED.technical_complexity,
  impact_level = EXCLUDED.impact_level, intensity_ceiling = EXCLUDED.intensity_ceiling;

