  ('skater-step', 'Use symptom-guided range and avoid breath-holding, excessive abdominal pressure, prolonged supine discomfort, or positions that create heaviness; choose supported alternatives for Skater Step when needed.', 'No default gender-based adjustment. Scale by training age, body size, limb length, leverage, joint tolerance, fatigue response, symptoms, and demonstrated control.'),
  ('crab-walk', 'Use symptom-guided range and avoid breath-holding, excessive abdominal pressure, prolonged supine discomfort, or positions that create heaviness; choose supported alternatives for Crab Walk when needed.', 'No default gender-based adjustment. Scale by training age, body size, limb length, leverage, joint tolerance, fatigue response, symptoms, and demonstrated control.')
) AS v(slug, guidance, gender_notes)
JOIN coaching.exercise e ON e.slug = v.slug
WHERE NOT EXISTS (
  SELECT 1 FROM coaching.exercise_scaling_profile sp
  WHERE sp.exercise_id = e.id AND sp.cohort_key = 'pregnancy_postpartum'
);

